addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  const sendgridApiKey = 'YOUR_SENDGRID_API_KEY';
  const stripeApiKey = 'YOUR_STRIPE_API_KEY';

  const sendgridUrl = 'https://api.sendgrid.com/v3/mail/send';
  const stripeUrl = 'https://api.stripe.com/v1/charges';

  const sendgridHeaders = {
    'Authorization': `Bearer ${sendgridApiKey}`,
    'Content-Type': 'application/json',
  };

  const stripeHeaders = {
    'Authorization': `Bearer ${stripeApiKey}`,
    'Content-Type': 'application/json',
  };

  try {
    if (request.url.includes('/send-email')) {
      const emailResponse = await fetch(sendgridUrl, {
        method: 'POST',
        headers: sendgridHeaders,
        body: JSON.stringify({ to: 'recipient@example.com', subject: 'Test Email', content: 'This is a test email.' }),
      });
      return new Response(JSON.stringify({ status: emailResponse.status, message: 'Email sent successfully' }), { status: emailResponse.status });
    } else if (request.url.includes('/process-payment')) {
      const paymentResponse = await fetch(stripeUrl, {
        method: 'POST',
        headers: stripeHeaders,
        body: JSON.stringify({ amount: 1000, currency: 'usd', source: 'tok_visa' }),
      });
      return new Response(JSON.stringify({ status: paymentResponse.status, message: 'Payment processed successfully' }), { status: paymentResponse.status });
    } else {
      return new Response('Invalid endpoint', { status: 404 });
    }
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 500 });
  }
}